insert into alternatives (id, slug, name, brand, basis_text, basis_confidence, basis_sources, affiliate_url, affiliate_type, category, image_url, asin, swap_type) values
  ('68033791-0381-4985-a5f9-f15c213c4375', 'bobs-red-mill-baking-soda', 'Baking Soda', 'Bob''s Red Mill', 'Founder Bob Moore was a committed Christian; multiple sources document his faith as the explicit motivation for company policy, including giving the company to employees via an ESOP.', 1, ARRAY['https://en.wikipedia.org/wiki/Bob_Moore_(executive)', 'https://www.klove.com/news/faith/founder-of-bob-s-red-mill-committed-christian-generous-boss-9757'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Bob''s%20Red%20Mill%20Baking%20Soda', NULL, 'christian'),
  ('da217333-a4ce-435a-a121-17830548d40a', 'boll-weevil-foaming-hand-wash', 'Foaming Hand Wash', 'Boll Weevil Soap Company', 'Explicitly self-identifies as a Christian-owned family soap business, citing Colossians 3:17 on its own About page. Note: only the Foaming Hand Wash is confirmed available on Amazon — Boll Weevil''s bar soap and body wash are not, and require a direct affiliate relationship instead.', 2, ARRAY['https://bollweevilsoapcompany.com/pages/about-us', 'https://www.amazon.com/Foaming-Boll-Weevil-Soap-Company/dp/B08RF27781'], NULL, 'amazon', 'Soap & Body', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Boll%20Weevil%20Foaming%20Hand%20Wash', 'B08RF27781', 'christian'),
  ('b550c0d3-3e25-4b68-8984-c14547e54ca3', 'faithfully-natural-soap-co', 'Soap / Body Wash', 'Faithfully Natural Soap Co.', 'Explicitly self-identifies as a Christian-owned family soap business on its own site.', 2, ARRAY['https://faithfullynaturalsoapco.com/pages/about-us'], 'https://faithfullynaturalsoapco.com', 'direct', 'Soap & Body', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Faithfully%20Natural%20Soap%20Co.', NULL, 'christian'),
  ('02ea9a7c-3a84-4fd7-8680-2104c8ce0f39', 'pure-hearts-clean-hands-soap-co', 'Soap / Body Wash', 'Pure Hearts & Clean Hands Soap Co.', 'Explicitly self-identifies as a Christian-owned family soap business on its own site.', 2, ARRAY['https://phchnaturalsoap.net/about-us/'], 'https://phchnaturalsoap.net', 'direct', 'Soap & Body', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Pure%20Hearts%20%26%20Clean%20Hands', NULL, 'christian'),
  ('99bd18d0-8f5b-437f-9f8a-d7b7e857b19c', 'branch-basics-all-purpose-concentrate', 'All-Purpose Cleaner Concentrate', 'Branch Basics', 'Co-founder Allison Evans states in a published interview, "we share a common faith, which we all fall back on," and founders discuss their Christian faith on the Thriving Beyond Belief podcast.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/', 'https://thrivingbeyondbelief.com/046-branch-basics-with-allison-evans-marilee-nelson/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20All-Purpose', NULL, 'christian'),
  ('0eb8cd5d-45c6-45c8-83c1-38cccce22d19', 'branch-basics-oxygen-boost', 'Oxygen Boost Stain Remover', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Oxygen%20Boost', NULL, 'christian'),
  ('28f2b271-b98f-4dca-9e1b-979448563b63', 'branch-basics-laundry-concentrate', 'Laundry Concentrate', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Laundry', NULL, 'christian'),
  ('1ac1e172-52e9-498d-84b1-39399364f49e', 'provherbs-herbal-supplements', 'Herbal Supplements / Tinctures', 'Provherbs', 'Company''s own "Our Story" page: "we look first to Christ. He is the center in all that we do."', 1, ARRAY['https://provherbs.com/pages/our-story'], 'https://provherbs.com', 'direct', 'Supplements', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Provherbs%20Supplements', NULL, 'christian'),
  ('8912e893-9647-4918-8302-abe3d8edd3a0', 'eleven86-artesian-water', 'Real Artesian Water', 'Eleven86', 'Company''s own tagline: "Faith in every drop. Purpose in every bottle."', 1, ARRAY['https://www.eleven86water.com/our-story'], 'https://www.eleven86water.com', 'unconfirmed', 'Food & Beverage', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Eleven86%20Water', NULL, 'christian'),
  ('8e90e55f-d98a-42c1-8cb1-abdad8b88b7a', 'bold3-coffee', 'Coffee (whole bean & ground)', 'BOLD3 Coffee', '501(c)(3) Christian nonprofit ministry. Own listing states: "BOLD3 Coffee is a Christian Non-profit Ministry on a mission to empower others to be BOLD and spread the Hope of Christ worldwide." Every bag purchased delivers God''s Word into the hands of 3 children.', 1, ARRAY['https://www.amazon.com/BOLD3-coffee-Colombian-Ethiopian-Nicaragua/dp/B07F2J6MHV', 'https://www.bold3.org/'], NULL, 'amazon', 'Food & Beverage', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=BOLD3%20Coffee', 'B07F2J6MHV', 'christian'),
  ('8d488aa6-ccc2-4093-bfff-cfdac0248e23', 'palm-beach-herbal-tea', 'Herbal Tea', 'Palm Beach Herbal Tea Company', 'Explicitly self-identifies as a "Christian based, family-owned herbal tea company" on its own site.', 1, ARRAY['https://palmbeachherbalteas.com/pages/our-story'], NULL, 'amazon', 'Food & Beverage', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Palm%20Beach%20Herbal%20Tea', NULL, 'christian'),
  ('0d28f051-e4f9-4398-bb21-7328a88679fb', 'everylife-diapers-wipes', 'Diapers + Wipes', 'EveryLife', 'Co-founders explicitly state "every child is a miracle from God"; company''s own mission page: "We unapologetically choose to celebrate life. Every child is a gift from above."', 1, ARRAY['https://everylife.com/pages/our-mission', 'https://www.oursundayvisitor.com/meet-the-founders-of-everylife-a-new-pro-life-diaper-company/'], 'https://everylife.com', 'unconfirmed', 'Baby Products', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=EveryLife%20Diapers', NULL, 'christian'),
  ('fa208758-062e-4cb6-ab33-2ecc769cf673', 'earth-eden-diapers', 'Diapers', 'Earth & Eden', 'Not a confirmed Christian-founded brand, but the closest Amazon-available, non-toxic, plant-based diaper option — offered as a secondary pick alongside EveryLife.', 2, ARRAY['https://www.earthandedenbrand.com/', 'https://www.amazon.com/Earth-Eden-Baby-Diapers-Count/dp/B07DYLJHLB'], NULL, 'amazon', 'Baby Products', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Earth%20%26%20Eden%20Diapers', 'B07DYLJHLB', 'christian'),
  ('cca96b87-761e-4a33-8342-b1772509db67', 'branch-basics-dishwasher-tablets', 'Dishwasher Tablets', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/', 'https://www.amazon.com/Branch-Basics-Dishwasher-Tablets-Fragrance-Free/dp/B0GNT5N4SP'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Dishwasher%20Tablets', 'B0GNT5N4SP', 'christian'),
  ('d87ffe99-ba0d-42c4-b5af-8b336ad9742f', 'branch-basics-laundry-detergent-powder', 'Laundry Detergent Powder', 'Branch Basics', 'Same founder faith basis as Branch Basics'' All-Purpose Concentrate.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Laundry%20Powder', NULL, 'christian'),
  ('682d4fde-be5a-42a1-8910-96314543434b', 'branch-basics-concentrate-oxygen-boost-bundle', 'Concentrate (33.8 oz) + Oxygen Boost (4 lbs) Bundle', 'Branch Basics', 'Concentrate replaces all-purpose cleaners and can be diluted for surface scrubbing; Oxygen Boost acts as a natural scouring powder and grout cleaner. Sold as a confirmed bundle listing on Amazon. Same founder faith basis as other Branch Basics entries.', 1, ARRAY['https://lexiscleankitchen.com/branch-basics-inteview/'], NULL, 'amazon', 'Household & Cleaning', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Branch%20Basics%20Bundle', NULL, 'christian'),
  ('01158fee-7740-4643-90d1-346df8b51308', 'toups-and-co-organics', 'Makeup & Skincare', 'Toups & Co. Organics', 'Christian family-owned, confirmed on the company''s own About page.', 1, ARRAY['https://toupsandco.com/pages/about-us'], NULL, 'amazon', 'Beauty & Makeup', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Toups%20%26%20Co.%20Organics', NULL, 'christian'),
  ('def9dd91-b5d8-4677-88c3-2d9f5c10a54d', 'jes-organics', 'Makeup, Skincare & Supplements', 'JES Organics', 'Own Amazon storefront states "Christian-based company founded in 2006."', 1, ARRAY['https://www.amazon.com/stores/JESOrganics/Homepage/page/34BCD59B-5770-4397-84F6-721513DA72D3'], NULL, 'amazon', 'Beauty & Makeup', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=JES%20Organics', NULL, 'christian'),
  ('2e7d0196-5039-4d82-9708-000bd999cc4b', 'hosanna-aroma', 'Christian Fragrance', 'Hosanna Aroma', 'Own website states "unapologetically Christian," Scripture-inspired, husband-and-wife team in Colorado, launched April 2024.', 1, ARRAY['https://hosanna-aroma.com/'], 'https://hosanna-aroma.com', 'direct', 'Beauty & Fragrance', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Hosanna%20Aroma', NULL, 'christian'),
  ('ad69fc98-dd31-45de-b169-3394e4e44fef', 'risen-fragrances', 'Christian Fragrance', 'Risen Fragrances', '"Exists to glorify God"; each scent is paired with Scripture, and $1 per bottle funds Bible distribution.', 1, ARRAY['https://risenfragrances.com/'], 'https://risenfragrances.com', 'direct', 'Beauty & Fragrance', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Risen%20Fragrances', NULL, 'christian'),
  ('058ee442-a10f-488f-b694-57ef82ad9fd3', 'leaf-razor-chrome', 'Leaf Razor (All-Metal Safety Razor, Chrome)', 'Leaf Shave', 'Clean/non-toxic alternative: all-metal, plastic-free razor with a pivoting head and no toxic shaving-strip chemicals. No Christian-founded claim has been found for Leaf Shave — this is offered as a clean swap, not a faith-based one.', 1, ARRAY['https://www.amazon.com/dp/B09QB2Y263', 'https://leafshave.com/'], NULL, 'amazon', 'Beauty & Personal Care', 'https://via.placeholder.com/400x600/CCCCCC/6B6B6B?text=Leaf%20Razor', 'B09QB2Y263', 'clean');
insert into associations (product_id, claim_text, source_urls, confidence_tier, theme_tag, date_checked) values
  ('49af0e89-d96d-4faf-913a-826b96ef52e8', 'Logo depicts Vulcan, the Roman god of fire and metalworking — confirmed by the company''s own brand history.', ARRAY['https://www.armandhammer.com/en/about-us', 'https://en.wikipedia.org/wiki/Arm_%26_Hammer', 'https://en.wikipedia.org/wiki/Vulcan_(mythology)'], 1, 'roman-mythology', '2026-07-01'),
  ('194c6fe3-dd8d-4706-9e80-e1ac89ae4b94', 'Founder Emanuel Bronner built the brand around a universalist "All-One-God-Faith" philosophy explicitly blending Judaism, Islam, and Christianity, not centered on Christianity specifically.', ARRAY['https://www.ucpress.edu/blog-posts/how-californias-dr-bronners-spiritual-messaging-became-a-global-brand', 'https://en.wikipedia.org/wiki/Emanuel_Bronner', 'https://info.drbronner.com/all-one-blog/2016/11/whole-crazy-trip-started/'], 1, 'universalist-syncretism', '2026-07-01'),
  ('6b0eb503-6369-4ec1-a6e2-4adc98374e0b', 'Entire collection is structured as a tarot-style "deck" of named fortune cards (The Illusionist, The Sovereign, The Sage, and more). Each bottle includes a QR code for a "shower reading" and a daily "manifestation." Method''s own product copy reads: "Are you ready to hear your fortune? Shoot for the stars today with a body wash that offers a glimpse into your future." This is scoped to the limited-edition Shower Readings line only — Method''s everyday cleaners carry no such theme and are not flagged.', ARRAY['https://methodproducts.com/pages/shower-readings', 'https://www.ulta.com/p/limited-edition-shower-readings-body-wash-pimprod2052565'], 1, 'fortune-telling', '2026-07-01'),
  ('986cd8a9-5651-4dab-9614-6bf90377fb99', 'The mascot was deliberately designed as a genie at P&G''s own direction. A 2014 NYT obituary for original illustrator Richard Black quotes P&G''s communications manager: the company wanted "magic from a bottle" represented by a genie, and the artist was directed to draw one. Genies/jinn originate in Arabic and Islamic folklore.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('0ef1d25d-6a68-4207-9600-cd72594a5cba', 'Named after Ajax (Telamonian Ajax), Greek mythological hero of the Trojan War, second in strength only to Achilles. Current marketing leans into it directly: "Stronger than dirt," with copy describing customers as "everyday heroes."', ARRAY['https://en.wikipedia.org/wiki/Ajax_the_Great', 'https://greekcitytimes.com/2022/06/03/hidden-ancient-greek-meaning-behind-ajax-brand-name/'], 1, 'greek-mythology', '2026-07-01'),
  ('6059c1bf-ae1f-45b2-96d0-13e305499a9d', 'Directly named after the Greek/Roman hero Hercules. The company''s own current product pages use the line "Behold the power of Hercules, products built to last and trusted by plumbers."', ARRAY['https://www.oatey.com/products/hercules-glug-kitchen-liquid-drain-opener--782826565'], 1, 'greek-mythology', '2026-07-01'),
  ('e0e72eec-6aff-4da2-a13e-3133c0cd3d40', 'Entire product line is built around named crystals with stated metaphysical properties (rose quartz for "joy," amethyst for "dream state," peridot for "balance and control your thoughts"). Marketing copy: "Call in your crystal super power. Crystal-infused and plant-powered."', ARRAY['https://www.pacificabeauty.com/collections/aromapower', 'https://www.ulta.com/brand/pacifica?category=fragrance'], 1, 'crystal-metaphysics', '2026-07-01'),
  ('0638e8a9-248a-48dc-a1dd-8db4ee7002dc', 'Founded by Yogi Bhajan, who introduced Kundalini Yoga to the US; the tea recipe and brand are explicitly built on Ayurvedic philosophy. The company''s own "our story" copy still cites Ayurveda as the foundation.', ARRAY['https://en.wikipedia.org/wiki/Yogi_Tea'], 1, 'ayurvedic', '2026-07-01'),
  ('c39b2b3e-b9de-435c-b695-1bd4b1527a13', 'Documented marketing campaigns built on witchcraft/occult themes: the company hired a self-described witch doctor in 2019 to publicly "hex" inventory as a Halloween stunt, and sold "sell your soul" branded merchandise with a mock contract for the buyer''s "Eternal Soul." These campaigns themselves are documented fact; describing the brand as "satanic" is contested commentary, not a company statement.', ARRAY['https://www.adweek.com/creativity/drink-at-your-own-risk-liquid-death-hires-witch-doctor-to-hex-its-water/', 'https://www.westernjournal.com/liquid-death-water-brand-offered-buy-customers-souls-even-offers-contract-put-satanic-deal-writing/'], 2, 'occult-marketing', '2026-07-01'),
  ('912ccc08-d16a-4ab2-a151-25e5f00c0f4c', 'Named directly after Gaia, the Greek primordial Earth goddess and mother of all life in Greek mythology. Confirmed by the founder''s own company history (founded 1986/1987 by herbalist Ric Scalzo).', ARRAY['https://www.peoplespharmacy.com/articles/introducing-gaia-herbs'], 1, 'greek-mythology', '2026-07-01'),
  ('f19b3968-9c5e-41cf-b7db-6718e155675c', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner — P&G''s own communications manager confirmed to the NYT that the mascot was deliberately designed as a genie.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('cdee20d7-df35-4929-9802-a90f7a26d861', 'Same brand-wide genie mascot association as Mr. Clean''s All-Purpose Cleaner.', ARRAY['https://en.wikipedia.org/wiki/Mr._Clean'], 1, 'islamic-folklore', '2026-07-01'),
  ('19d7429c-ad39-42a7-bd3b-58d61e6cf1b7', 'Brand name is explicitly drawn from an ancient Iroquois Great Law of Peace philosophy. The company''s own website states: "Our name is inspired by an ancient Iroquois philosophy which instructs that in our every deliberation, we must consider the impact of our decisions on the next seven generations."', ARRAY['https://www.seventhgeneration.com/blog/origin-our-name-seventh-generation', 'https://www.fastcompany.com/665006/great-law-iroquois-confederacy'], 1, 'indigenous-philosophy', '2026-07-01'),
  ('2e3dd424-6bc2-4e5c-9041-9a7541d858c3', 'Logo is a twin-tailed siren from Greek mythology, confirmed on the company''s own "Story of the Siren" page: "it depicted a siren, a seductive twin-tailed mermaid from Greek mythology who enticed passing sailors to their doom with her enchanting song."', ARRAY['https://about.starbucks.com/history/the-story-of-the-siren/'], 1, 'greek-mythology', '2026-07-01'),
  ('70531ae1-228b-4d4d-a1d4-3b6bff9a850e', 'Name and branding deliberately center on death-themed imagery. The company''s own website states: "To some, a death wish may sound irresponsible, morbid, a step too far — but we believe it is the boldest sign of living life to the fullest." This is secular dark/death-themed branding, not tied to a specific mythology or occult practice.', ARRAY['https://www.forbes.com/sites/forbestreptalks/2016/02/09/meet-the-entrepreneur-behind-the-super-bowl-coffee-ad/', 'https://en.wikipedia.org/wiki/Death_Wish_Coffee'], 1, 'secular-death-themed', '2026-07-01'),
  ('12868039-1acd-4d83-8e25-e92d97e57b82', 'Founder Jessica Alba publicly shared Instagram content in August 2024 involving occult/spiritual practices (numerology, astrology, crystals, and sage burning). Alba had stepped down as Chief Creative Officer in April 2024, before the posts, so she was no longer a company officer at the time, and the brand''s own products carry no occult imagery or branding. This is the founder''s personal social media activity, not a company branding decision.', ARRAY['https://www.instagram.com/p/C_bp7Qpu-hr/'], 2, 'founder-personal-conduct', '2026-07-01'),
  ('eebb36fc-9f83-48d9-b750-826c4cc2a9ad', 'Logo depicts Vulcan, the Roman god of fire and metalworking — confirmed by the company''s own brand history. Same brand-wide association as the Arm & Hammer baking soda entry.', ARRAY['https://www.armandhammer.com/en/about-us', 'https://en.wikipedia.org/wiki/Arm_%26_Hammer', 'https://en.wikipedia.org/wiki/Vulcan_(mythology)'], 1, 'roman-mythology', '2026-07-03'),
  ('58e843f7-fa6d-486b-8ead-00953c2163bf', 'Named after Ajax (Telamonian Ajax), the Greek mythological hero of the Trojan War. Same brand-wide association as the Ajax Powder Cleanser entry.', ARRAY['https://en.wikipedia.org/wiki/Ajax_the_Great', 'https://greekcitytimes.com/2022/06/03/hidden-ancient-greek-meaning-behind-ajax-brand-name/'], 1, 'greek-mythology', '2026-07-03'),
  ('a598977b-ee02-453c-8133-34c1a9cc7977', 'Brand name is explicitly drawn from an ancient Iroquois Great Law of Peace philosophy. Same brand-wide association as the Seventh Generation Laundry Detergent entry.', ARRAY['https://www.seventhgeneration.com/blog/more-than-a-name', 'https://en.wikipedia.org/wiki/Seventh_Generation_Inc.'], 1, 'indigenous-philosophy', '2026-07-03'),
  ('bdf96ebb-839c-43fb-bb3b-30c805f77a94', 'Named after Nyx, the Greek goddess of the night. Confirmed by founder Toni Ko''s own statements at the brand''s 1999 launch.', ARRAY['https://en.wikipedia.org/wiki/NYX_Cosmetics', 'https://www.allure.com/story/nyx-professional-makeup-founder-toni-ko'], 1, 'greek-mythology', '2026-07-03'),
  ('f700f8a2-594c-4bbc-a077-6b56433d7f7d', 'Founders deliberately built the brand around dark/rebellious aesthetic choices confirmed in their own words. Product lines include "Perversion" mascara, "Vice" palettes, "Naked" palettes, and "Sin" eyeshadow. Co-founders described themselves as "co-conspirators" in published interviews. This is dark aesthetic branding by the founders'' own choice, not a specific mythology or belief-system tie.', ARRAY['https://en.wikipedia.org/wiki/Urban_Decay_(cosmetics)', 'https://www.allure.com/story/urban-decay-history'], 1, 'secular-dark-aesthetic', '2026-07-03'),
  ('1f33b66b-2f1b-4e28-a4c1-f3d9f9732daf', 'Founder Amanda Chantal Bacon describes the company as "a cosmic beacon" in her own interviews, references astrology and crystal energy throughout the brand''s marketing, and publicly stated of a stolen store crystal, "You do not want the energy of a stolen crystal." Company''s own marketing describes Moon Juice as "a healing force, an etheric potion, a cosmic beacon."', ARRAY['https://www.theguardian.com/lifeandstyle/2015/jan/16/moon-juice-food-for-beautiful-people', 'https://moonjuice.com/pages/about'], 1, 'astrology-crystal-energy', '2026-07-03'),
  ('da597ad6-0ee2-4d26-a0de-58b5ba8ccaca', 'Bottle is a five-pointed star, described in the company''s own marketing as "a celestial bottle: a five-pointed star evoking womanhood, protection and destiny." Company''s own copy calls it "a cosmic object that appears supernaturally out of space" and "the embodiment of dreams."', ARRAY['https://www.mugler.com/en-us/angel', 'https://en.wikipedia.org/wiki/Angel_(fragrance)'], 1, 'celestial-supernatural', '2026-07-03'),
  ('841ca8e2-00be-4cd4-b6ab-f3169eaeb087', 'Named after Venus, the Roman goddess of love and beauty. Company''s own brand platform and tagline: "Reveal the goddess in you." The company''s own brand team confirmed the internal creative platform as "every woman can feel like a goddess."', ARRAY['https://gillette.com/en-us/venus', 'https://en.wikipedia.org/wiki/Gillette_Venus'], 1, 'roman-mythology', '2026-07-03');
